#!/bin/bash\n# FreeAutotune Build Script for Linux\n\nset -e\n\necho \"🎵 FreeAutotune Build Script (Linux)\"\necho \"=====================================\"\necho \"\"\n\n# Check dependencies\necho \"📋 Checking dependencies...\"\nwhich cmake > /dev/null || { echo \"❌ CMake not found. Install: sudo apt install cmake\"; exit 1; }\nwhich g++ > /dev/null || { echo \"❌ GCC not found. Install: sudo apt install build-essential\"; exit 1; }\npkg-config --exists soundtouch || { echo \"⚠️  SoundTouch not found. Install: sudo apt install libsoundtouch-dev\"; }\n\n# Check if JUCE submodule exists\nif [ ! -d \"JUCE\" ]; then\n    echo \"📦 Adding JUCE submodule...\"\n    git submodule add https://github.com/juce-framework/JUCE.git\nfi\n\n# Create build directory\nif [ ! -d \"build\" ]; then\n    mkdir build\nfi\n\ncd build\n\necho \"🔨 Generating build files...\"\ncmake ..\n\necho \"🔨 Building FreeAutotune (this may take a few minutes)...\"\ncmake --build . --config Release -- -j$(nproc)\n\necho \"\"\necho \"✅ Build complete!\"\necho \"\"\necho \"Plugin location:\"\necho \"  • VST3: ./FreeAutotune_artefacts/Release/VST3/\"\necho \"\"\necho \"To install:\"\necho \"  • mkdir -p ~/.vst3\"\necho \"  • cp -r FreeAutotune_artefacts/Release/VST3/FreeAutotune.vst3 ~/.vst3/\"\n"